def orifice_typeSMALL(reg):
    suf = reg[-2:]
    if suf == "18":
        return '1/8"'
    elif suf == "36":
        return '3/16"'
    elif suf == "14":
        return '1/4"'
    elif suf == "56":
        return '5/16"'
    elif suf == "38":
        return '3/8"'
    elif suf == "12":
        return '1/2"'

def orifice_max496(reg):
    suf = reg[-2:]
    if suf == "18":
        return 125
    elif suf == "36":
        return 125
    elif suf == "14":
        return 60
    elif suf == "56":
        return 40
    elif suf == "38":
        return 30
    elif suf == "12":
        return 30

# Spring Selections
