def spring_496(op):
    if op < 6/28 and op >= 3.5/28:
        return {
            'color': 'Silver',
            'range': '(3.5" - 10.5" wc)',
        }
    elif op < 8/28:
        return {
            'color': 'Blue',
            'range': '(6" - 8" wc)',
        }
    elif op < 14/28:
        return {
            'color': 'Green',
            'range': '(6" - 14" wc)',
        }
    elif op < 1:
        return {
            'color': 'Red',
            'range': '(12" - 28" wc)',
        }
    elif op <= 2:
        return {
            'color': 'Black',
            'range': '(1 - 2 psi)',
        }
    

# Will Regulator Work Function & Will IRV Work
# ------------------------------------------------------------------------------------------------------

def will_work(cap, reg, orifice_max):
    if cap == "N/A":
        return "No"
    else:
        if cap >= (flow_rate * oversizeby) and orifice_max >= maop:
            return "Yes"
        else:
            return "No"

