    if outlet_input <= 4.5 or (outlet_input <= 5 and opp == "IRV" and partial):
        data_used243 = stddata243
    else:
        data_used243 = hpdata243

    if opp == "IRV" and not partial:
        result = interpolate_capacity(data_used243, inlet, outlet, False, False)
        if isinstance(result, str):
            warning = result
            result = None
            match = None
            apply = False
            return result, match, apply, warning

        # Try with IRV
        match = gen_match243(result, opp)

        if match:
            apply = True
            warning = "Sized with IRV"
        # IRV does not work- try with Monitor
        else:

            # Need to change 243 data used to HP data for pressures > 4.5 psi
            if outlet_input > 4.5:
                data_used243 = hpdata243
                
            result = interpolate_capacity(data_used243, inlet, outlet, True, False)
            if isinstance(result, str):
                warning = result
                result = None
                match = None
                apply = False
                return result, match, apply, warning

            match = gen_match243(result, "Monitor")

            if match:
                apply = True
                warning = "IRV curves did not work for your application, sized for worker/monitor setup"
            else:
                apply = False      

    # size for monitor
    elif opp == "Monitor":
        result = interpolate_capacity(data_used243, inlet, outlet, True, False)
        if isinstance(result, str):
            warning = result
            result = None
            match = None
            apply = False
            return result, match, apply, warning

        match = gen_match243(result, opp)

        apply = False
        if match:
            apply = True
            if hp_warning != None:
                warning = hp_warning
            else:
                warning = "Sized for worker/monitor setup"

    # no overpressure protection or partial IRV
    else:
        result = interpolate_capacity(data_used243, inlet, outlet, False, False)
        if isinstance(result, str):
            warning = result
            result = None
            match = None
            apply = False
            return result, match, apply, warning

        match = gen_match243(result, opp)

        if match:
            apply = True
        else:
            apply = False
    
    return result, match, apply, warning


