def orifice_typeSMALL(reg):
    suf = reg[-2:]
    if suf == "18":
        return '1/8"'
    elif suf == "36":
        return '3/16"'
    elif suf == "14":
        return '1/4"'
    elif suf == "56":
        return '5/16"'
    elif suf == "38":
        return '3/8"'
    elif suf == "12":
        return '1/2"'
    return "Unknown"

def orifice_max046(reg):
    suf = reg[-2:]
    if outlet_input < 10:
        if suf == "18":
            return 500
        elif suf == "36":
            return 500
        elif suf == "14":
            return 500
        elif suf == "56":
            return 300
        elif suf == "38":
            return 300
        elif suf == "12":
            return 100
    elif outlet_input < 125:
        if suf == "18":
            return 1000
        elif suf == "36":
            return 1000
        elif suf == "14":
            return 500
        elif suf == "56":
            return 400
        elif suf == "38":
            return 300
        elif suf == "12":
            return 100
    else:
        if suf == "18":
            return 1000
        elif suf == "36":
            return 1000
        elif suf == "14":
            return 500
        elif suf == "56":
            return 400
        elif suf == "38":
            return 400
        elif suf == "12":
            return 100


# Spring Selections
# ------------------------------------------------------------------------------------------------------

def spring_046(op):
    if op < 10 and op >= 3:
        return {
            'color': "Yellow",
            'range': "(3 – 10 psi)",
        }
    elif op < 20:
        return {
            'color': "Aluminum",
            'range': "(8 - 20 psi)"
        }
    elif op < 52:
        return {
            'color': "White",
            'range': "(15 – 52 psi)"
        }
    elif op < 95:
        return {
            'color': "Green",
            'range': "(10 – 95 psi)"
        }
    elif op <= 125:
        return {
            'color': "Tan",
            'range': "(50 – 125 psi)"
        }
    elif op <= 200:
        return {
            'color': "Gray",
            'range': "(100 - 200 psi *cannot be used with 046-2)"
        }


