# Regulator Match Functions
# ------------------------------------------------------------------------------------------------------

def gen_match046(result, opp):
    match = None

    std_body_labels046 = {
        'R046134': '3/4"',
        'R046110': '1"',
        'R04611Q': '1-1/4"',
    }

    irv_body_labels046 = {
        'R046234': '3/4"',
        'R046210': '1"',
        'R04621Q': '1-1/4"',
    }

    std_pipe_priority = {
        '3/4"': 'R046134',
        '1"':    'R046110',
        '1-1/4"': 'R04611Q',
    }

    irv_pipe_priority = {
        '3/4"': 'R046234',
        '1"':    'R046210',
        '1-1/4"': 'R04621Q',
    }

    all_std_prefixes = list(std_body_labels046.keys())
    prioritized_std = std_pipe_priority.get(pipesize_input)
    if prioritized_std:
        ordered_std_prefixes = [prioritized_std] + [p for p in all_std_prefixes if p != prioritized_std]
    else:
        ordered_std_prefixes = all_std_prefixes

    all_irv_prefixes = list(irv_body_labels046.keys())
    prioritized_irv = irv_pipe_priority.get(pipesize_input)
    if prioritized_irv:
        ordered_irv_prefixes = [prioritized_irv] + [p for p in all_irv_prefixes if p != prioritized_irv]
    else:
        ordered_irv_prefixes = all_irv_prefixes

    orifice_order = ['12', '38', '56', '14', '36', '18']

    #seat logic
    diff = inlet_input - outlet_input
    seat = 'Poly-Tan'
    if maop < 600 and diff < 400:
        seat = 'Poly-Tan'

    # IRV sizing
    if opp == "IRV":
        for prefix in ordered_irv_prefixes:
            for orifice in orifice_order:
                reg = f"{prefix}_{orifice}"
                if reg in result:
                    cap = result[reg]
                    if will_work(cap, reg, orifice_max046(reg)) == "Yes" and will_irv_work046(reg, irv_input) != "No":
                        match = {
                            'reg' : reg,
                            'model': '046-2',
                            'diap': None,
                            'body': irv_body_labels046[prefix],
                            'orifice': orifice_typeSMALL(reg),
                            'seat': seat,
                            'color': spring_046(outlet_input)['color'],
                            'range': spring_046(outlet_input)['range'],
                            'capacity': cap,
                            'opp': "IRV",
                        }
                        return match
    # STD sizing
    else:
        for prefix in ordered_std_prefixes:
            for orifice in orifice_order:
                reg = f"{prefix}_{orifice}"
                if reg in result:
                    cap = result[reg]
                    if will_work(cap, reg, orifice_max046(reg)) == "Yes":
                        match = {
                            'reg' : reg,
                            'model': '046',
                            'diap': None,
                            'body': std_body_labels046[prefix],
                            'orifice': orifice_typeSMALL(reg),
                            'seat': seat,
                            'color': spring_046(outlet_input)['color'],
                            'range': spring_046(outlet_input)['range'],
                            'capacity': cap,
                            'opp': opp,
                        }
                        return match

def run_regulator_selection046(inlet, outlet, opp):

    warning = None

    if opp == "IRV" and not partial:
        result = interpolate_capacity(data046, inlet, outlet, False, False)

        if isinstance(result, str):
            warning = result
            result = None
            match = None
            apply = False
            return result, match, apply, warning

        # Try with IRV
        match = gen_match046(result, opp)

        if match:
            apply = True
            warning = "Sized with IRV"
        # IRV does not work- try with Monitor
        else:
            result = interpolate_capacity(data046, inlet, outlet, True, False)
            if isinstance(result, str):
                warning = result
                result = None
                match = None
                apply = False
                return result, match, apply, warning
            
            match = gen_match046(result, "Monitor")

            if match:
                apply = True
                warning = "IRV curves did not work for your application, sized for worker/monitor setup"
            else:
                apply = False

    # Monitor or no overpressure protection or partial IRV
    else:
        if opp == "Monitor":
            result = interpolate_capacity(data046, inlet, outlet, True, False)
        else:
            result = interpolate_capacity(data046, inlet, outlet, False, False)
        
        if isinstance(result, str):
                warning = result
                result = None
                match = None
                apply = False
                return result, match, apply, warning
        
        match = gen_match046(result, opp)

        if match:
            apply = True
            if opp == "Monitor":
                warning = "Sized for worker/monitor setup"
        else:
            apply = False
    
    return result, match, apply, warning


# Part Number Configurator
# ------------------------------------------------------------------------------------------------------

def hsc_pnc046(match):
    body_map = {
        '3/4"': '3/4',
        '1"': '1',
        '1-1/4"': '1-1/4',
    }
    orifice_map = {
        '1/8"': "10",
        '3/16"': "11",
        '1/4"': "12",
        '5/16"': "13",
        '3/8"': "14",
        '1/2"': "15",
    }
    spring_map = {
        'Yellow': '23',
        'Aluminum': '24',
        'White': '25',
        'Green': '28',
        'Tan': '26',
        'Gray': '27',
    }

    model = match['model']
    body = body_map.get(match['body'])
    orifice = orifice_map.get(match['orifice'])
    seat = 'TAN' # NetSuite only uses TAN orifice on most models
    spring = spring_map.get(match['color'])

    if model == '046-2':
        return f"R.046-2.IRV.{body}.IRV.{orifice}.{seat}.{spring}.ALU"
    elif model == '046' and match['opp'] != "Monitor":
        return f"R.046-1.STD.{body}.{orifice}.{seat}.{spring}.ALU"
    # Under 125 psi setpoint - use 046-2M for monitor
    elif spring != '27':
        return [
            f"R.046-2M.MON.{body}.IRV.{orifice}.{seat}.{spring}.ALU",
            f"R.046-1.STD.{body}.{orifice}.{seat}.{spring}.ALU",
        ]
    # over 125 psi setpoint - use 046-M for monitor
    else:
        return [
            f"R.046-M.MON.{body}.{orifice}.{seat}.{spring}.ALU",
            f"R.046-1.STD.{body}.{orifice}.{seat}.{spring}.ALU",
        ]


