# Body Types & MAOP Function
# ------------------------------------------------------------------------------------------------------

def body_type121(reg):
    suf = reg[-2:]
    if suf == "13":
        return '3/4" or 1"'
    elif suf == "10":
        return '1"'
    elif suf == "1Q":
        return '1-1/4"'
    elif suf == "1H":
        return '1-1/2"'
    elif suf == "20":
        return '2"'
    elif suf == "2H":
        return '2-1/2"'
    elif suf == "30":
        return '3"'
    return "Unknown"

def body_max121(reg):
    pre = reg[:6]
    suf = reg[-2:]
    if pre == 'R12208' or pre == 'R12212':
        return 15
    elif suf == '30':
        return 40
    else:
        return 60


# Spring Selection
# ------------------------------------------------------------------------------------------------------

def spring_121_122(op, reg):
    if reg == 'R1210813' or reg == 'R121081Q':
        if op >= 1.5/28 and op <= 3.5/28:
            return {
                'color': 'Blue-Black with Black-Red counter',
                'range': '(1.5" - 3.5" wc)',
            }
        elif op < 6.5/28:
            return {
                'color': 'Red-Black',
                'range': '(3.5" - 6.5" wc)',
            }
        elif op < 8.5/28:
            return {
                'color': 'Blue-Black',
                'range': '(5" - 8.5" wc)',
            }
        elif op < 14/28:
            return {
                'color': 'Green-Black',
                'range': '(12" - 28" wc)',
            }
        elif op <= 1:
            return {
                'color': 'Green',
                'range': '(12" - 28" wc)',
            }
        elif op <= 2:
            return {
                'color': 'Orange',
                'range': '(1 - 2 psi)',
            }
        elif op <= 4.25:
            return {
                'color': 'Black',
                'range': '(2 - 4.25 psi)',
            }
    elif reg == 'R121081H' or reg == 'R1210820' or reg == 'R121082H':
        if op >= 1 and op <= 2:
            return {
                'color': 'Orange',
                'range': '(1 - 2 psi)',
            }
        elif op <= 4.25:
            return {
                'color': 'Black',
                'range': '(2 - 4.25 psi)',
            }
    elif reg == 'R121121H' or reg == 'R1211220' or reg == '121122H':
        if op >= 1.5/28 and op <= 3.5/28:
            return {
                'color': 'Red with counter',
                'range': '(1.5" - 3.5" wc)',
            }
        elif op < 6.5/28:
            return {
                'color': 'Red',
                'range': '(3.5" - 6.5" wc)',
            }
        elif op < 8.5/28:
            return {
                'color': 'Blue',
                'range': '(5" - 8.5" wc)',
            }
        elif op < 14/28:
            return {
                'color': 'Green',
                'range': '(6" - 14" wc)',
            }
        elif op <= 1:
            return {
                'color': 'Orange',
                'range': '(12" - 28" wc)',
            }
        elif op < 2:
            return {
                'color': 'Black',
                'range': '(1 - 2 psi)',
            }
        elif op <= 3:
            return {
                'color': 'Cadmium',
                'range': '(1.5 - 3 psi)',
            }
    elif reg == 'R1211230':
        if op >= 1 and op < 2:
            return {
                'color': 'Black',
                'range': '(1 - 2 psi)',
            }
        elif op <= 3:
            return {
                'color': 'Cadmium',
                'range': '(1.5 - 3 psi)',
            }
    elif reg == 'R1211630':
        if op >= 3.5/28 and op < 6.5/28:
            return {
                'color': 'Red',
                'range': '(3.5" - 6.5" wc)',
            }
