# Will Regulator Work Function
# ------------------------------------------------------------------------------------------------------

def will_work_vp(cap, reg, vp):
    if cap == "N/A":
        return "No"
    else:
        if vp:
            min = 40
        else:
            min = 20
        
        if cap >= (flow_rate * oversizeby) and (cap / min) <= min_flow and body_max121(reg) >= maop:
            return "Yes"
        else:
            return "No"


