# Regulator Match Functions
# ------------------------------------------------------------------------------------------------------

def gen_match121(result121, result122, vp, opp):
    
    match = None

    if vp:

        body_order121 = ['1H', '20', '2H']

        vp_pipe_priority = {
            '1-1/2"': ['1H'],
            '2"':   ['20'],
            '2-1/2"': ['2H'],
        }
        priority_list = vp_pipe_priority.get(pipesize_input, [])
        ordered_body121 = priority_list + [b for b in body_order121 if b not in priority_list]

        model_labels_121 = {
            'R12108': '121-8',
            'R12112': '121-12',
        }

        # -------- 121 Standard only --------
        if outlet_input <= 3:
        
            for prefix, label in model_labels_121.items():
                for body in ordered_body121:
                    reg = f"{prefix}{body}"
                    if reg in result121:
                        cap = result121[reg]
                        if will_work_vp(cap, reg, vp) == "Yes":
                            match = {
                                'reg': reg,
                                'model': model_labels_121[prefix],
                                'diap': None,
                                'body': body_type121(reg),
                                'orifice': "V-Port",
                                'seat': None,
                                'color': spring_121_122(outlet_input, reg)['color'],
                                'range': spring_121_122(outlet_input, reg)['range'],
                                'capacity': cap,
                                'opp': opp,
                            }
                            return match
        # -------- 121 HP --------    
        else:
            for body in ordered_body121:
                reg = f"R121HP{body}"
                if reg in result121:
                    cap = result121[reg]
                    if will_work_vp(cap, reg, vp) == "Yes":
                        match = {
                            'reg': reg,
                            'model': '121-8-HP',
                            'diap': None,
                            'body': body_type121(reg),
                            'orifice': "V-Port",
                            'seat': None,
                            'color': spring_121_122(outlet_input, reg)['color'],
                            'range': spring_121_122(outlet_input, reg)['range'],
                            'capacity': cap,
                            'opp': opp,
                        }
                        return match
    
    # NO VP -----------------------------------------------------------
    else:

        body_order121 = ['13', '10', '1Q', '1H', '20', '2H', '30']

        novp_pipe_priority = {
            '3/4"': ['13'],
            '1"':    ['13', '10'],
            '1-1/4"': ['1Q'],
            '1-1/2"':  ['1H'],
            '2"':    ['20'],
            '2-1/2"':  ['2H'],
            '3"':    ['30'],
        }
        priority_list = novp_pipe_priority.get(pipesize_input, [])
        ordered_body121 = priority_list + [b for b in body_order121 if b not in priority_list]

        model_labels_121122 = {
            'R12108': '121-8',
            'R12112': '121-12',
            'R12116': '121-16',
            'R12208': '122-8',
            'R12212': '122-12',
        }

        model_labels_121 = {
            'R12108': '121-8',
            'R12112': '121-12',
            'R12116': '121-16',
        }

        # -------- 121 or 122 Standard --------
        if outlet_input <= 2 and isinstance(result122, str) == False:

            for prefix, label in model_labels_121122.items():
                res = result121 if prefix.startswith('R121') else result122
                for body in ordered_body121:
                    reg = f"{prefix}{body}"
                    if reg in res:
                        cap = res[reg]
                        if will_work_vp(cap, reg, vp) == "Yes":
                            match = {
                                'reg': reg,
                                'model': model_labels_121122[prefix],
                                'diap': None,
                                'body': body_type121(reg),
                                'orifice': None,
                                'seat': None,
                                'color': spring_121_122(outlet_input, reg)['color'],
                                'range': spring_121_122(outlet_input, reg)['range'],
                                'capacity': cap,
                                'opp': opp,
                            }
                            return match
        
        # -------- 121 Standard only --------
        elif outlet_input <= 3:
        
            for prefix, label in model_labels_121.items():
                for body in ordered_body121:
                    reg = f"{prefix}{body}"
                    if reg in result121:
                        cap = result121[reg]
                        if will_work_vp(cap, reg, vp) == "Yes":
                            match = {
                                'reg': reg,
                                'model': model_labels_121[prefix],
                                'diap': None,
                                'body': body_type121(reg),
                                'orifice': None,
                                'seat': None,
                                'color': spring_121_122(outlet_input, reg)['color'],
                                'range': spring_121_122(outlet_input, reg)['range'],
                                'capacity': cap,
                                'opp': opp,
                            }
                            return match
        # -------- 121 HP --------    
        else:
            for body in ordered_body121:
                reg = f"R121HP{body}"
                if reg in result121:
                    cap = result121[reg]
                    if will_work_vp(cap, reg, vp) == "Yes":
                        match = {
                            'reg': reg,
                            'model': '121-8-HP',
                            'diap': None,
                            'body': body_type121(reg),
                            'orifice': None,
                            'seat': None,
                            'color': spring_121_122(outlet_input, reg)['color'],
                            'range': spring_121_122(outlet_input, reg)['range'],
                            'capacity': cap,
                            'opp': opp,
                        }
                        return match

def run_regulator_selection121(inlet, outlet, opp):
    # Select 121 Data Table
    if outlet_input <= 3:
        data_used121 = stddata121
    else:
        data_used121 = hpdata121

    if opp == "Monitor":
        monitor = True
        warning = "Sized for worker/monitor setup"
    else:
        monitor = False
        warning = None

    vp = False
    result121 = interpolate_capacity(data_used121, inlet, outlet, monitor, False)
    result121_VP = interpolate_capacity(data_used121, inlet, outlet, monitor, True)

    if isinstance(result121, str):
        warning = result121
        result121 = None
        result121_VP = None
        result122 = None
        match = None
        apply = False
        return result121, result121_VP, result122, match, apply, warning

    # 122 can only be used up to 2 psi outlet
    result122 = interpolate_capacity(stddata122, inlet_input, outlet_input, monitor, vp)
        
    match = gen_match121(result121, result122, vp, opp)

    if match:
        apply = True
    else:
        # Try V-Port
        vp = True
        match = gen_match121(result121_VP, result122, vp, opp)

        if match:
            apply = True
        else:
            apply = False

    return result121, result121_VP, result122, match, apply, warning


